 1	import React, { FC, useCallback, useEffect, useState } from 'react';
 2	import { useNavigate } from 'react-router-dom-v5-compat';
 3	import { useLocation } from 'react-router-dom-v5-compat';
 4	
 5	import useInstanceTypesAndPreferences from '@catalog/CreateFromInstanceTypes/state/hooks/useInstanceTypesAndPreferences';
 6	import GuidedTour from '@kubevirt-utils/components/GuidedTour/GuidedTour';
 7	import { VirtualMachineDetailsTab } from '@kubevirt-utils/constants/tabs-constants';
 8	import { getName } from '@kubevirt-utils/resources/shared';
 9	import useInstanceTypeExpandSpec from '@kubevirt-utils/resources/vm/hooks/useInstanceTypeExpandSpec';
10	import useVMI from '@kubevirt-utils/resources/vm/hooks/useVMI';
11	import { Tab, Tabs, TabTitleText } from '@patternfly/react-core';
12	import { NavPageComponentProps } from '@virtualmachines/details/utils/types';
13	
14	import { getNamespace } from '../../../../cdi-upload-provider/utils/selectors';
15	
16	import VirtualMachineConfigurationTabSearch from './search/VirtualMachineConfigurationTabSearch';
17	import { getInnerTabFromPath, includesConfigurationPath, tabs } from './utils/utils';
18	
19	import './virtual-machine-configuration-tab.scss';
20	
21	const VirtualMachineConfigurationTab: FC<NavPageComponentProps> = ({ obj }) => {
22	  const navigate = useNavigate();
23	  const location = useLocation();
24	
25	  const { vmi } = useVMI(getName(obj), getNamespace(obj));
26	  const { allInstanceTypes } = useInstanceTypesAndPreferences();
27	  const [instanceTypeVM] = useInstanceTypeExpandSpec(obj);
28	  const [activeTabKey, setActiveTabKey] = useState<number | string>(
29	    VirtualMachineDetailsTab.Details,
30	  );
31	
32	  const redirectTab = useCallback(
33	    (name: string) => {
34	      setActiveTabKey(name);
35	      const redirectPath = includesConfigurationPath(
36	        location.pathname,
37	        `${VirtualMachineDetailsTab.Configurations}/${name}`,
38	      );
39	      navigate(redirectPath);
40	    },
41	    [location.pathname, navigate],
42	  );
43	
44	  useEffect(() => {
45	    const innerTab = getInnerTabFromPath(location.pathname);
46	    innerTab && setActiveTabKey(innerTab);
47	  }, [location.pathname]);
48	
49	  return (
50	    <div className="co-dashboard-body VirtualMachineConfigurationTab">
51	      <VirtualMachineConfigurationTabSearch vm={obj} />
52	      <div className="VirtualMachineConfigurationTab--body">
53	        <Tabs activeKey={activeTabKey} className="VirtualMachineConfigurationTab--main" isVertical>
54	          {tabs.map(({ Component, name, title }) => (
55	            <Tab
56	              className="VirtualMachineConfigurationTab--content"
57	              data-test-id={`vm-configuration-${name}`}
58	              eventKey={name}
59	              key={name}
60	              onClick={() => redirectTab(name)}
61	              title={<TabTitleText>{title}</TabTitleText>}
62	            >
63	              {activeTabKey === name && (
64	                <Component
65	                  allInstanceTypes={allInstanceTypes}
66	                  instanceTypeVM={instanceTypeVM}
67	                  vm={obj}
68	                  vmi={vmi}
69	                />
70	              )}
71	            </Tab>
72	          ))}
73	        </Tabs>
74	      </div>
75	      <GuidedTour />
76	    </div>
77	  );
78	};
79	
80	export default VirtualMachineConfigurationTab;

